from __future__ import annotations
from dataclasses import dataclass, field
from enum import Enum
from typing import Optional


class MitigationStrategy(Enum):
    MITIGATE           = "mitigate"
    TRANSFER           = "transfer"
    REDUCE_PROBABILITY = "reduce_probability"
    ACCEPT             = "accept"


class MitigationTaskStatus(Enum):
    TODO        = "todo"
    IN_PROGRESS = "in_progress"
    DONE        = "done"
    BLOCKED     = "blocked"


@dataclass
class MitigationTask:
    task_id: str
    description: str
    owner: str                   # role (e.g. "AI Safety Lead", "Engineering Lead")
    acceptance_criterion: str    # verifiable statement: test, threshold, review outcome
    status: MitigationTaskStatus = MitigationTaskStatus.TODO
    linked_ticket: str = ""      # Jira/Linear/GitHub issue ID
    notes: str = ""

    @property
    def is_complete(self) -> bool:
        return self.status == MitigationTaskStatus.DONE


@dataclass
class MitigationPlan:
    plan_id: str
    risk_id: str                    # matches RiskEntry.risk_id in the register
    risk_title: str
    strategy: MitigationStrategy
    tasks: list[MitigationTask] = field(default_factory=list)
    fallback_if_fails: str = ""    # what to do if mitigation cannot be completed before launch

    def add_task(self, task: MitigationTask) -> None:
        self.tasks.append(task)

    @property
    def all_tasks_complete(self) -> bool:
        return all(t.is_complete for t in self.tasks)

    @property
    def is_build_ready(self) -> bool:
        """Plan is ready for build to start only when all tasks have an owner and criterion."""        return all(
            t.owner and t.acceptance_criterion
            for t in self.tasks
        )

    @property
    def is_launch_ready(self) -> bool:
        """All mitigation tasks must be DONE before the feature ships."""        return self.all_tasks_complete

    def blocked_tasks(self) -> list[MitigationTask]:
        return [t for t in self.tasks if t.status == MitigationTaskStatus.BLOCKED]

    def summary(self) -> dict:
        return {
            "plan_id": self.plan_id,
            "risk_id": self.risk_id,
            "strategy": self.strategy.value,
            "total_tasks": len(self.tasks),
            "done": sum(1 for t in self.tasks if t.is_complete),
            "blocked": len(self.blocked_tasks()),
            "is_build_ready": self.is_build_ready,
            "is_launch_ready": self.is_launch_ready,
        }

from dataclasses import dataclass, field


@dataclass
class MitigationPlanRegistry:
    feature_id: str
    plans: list[MitigationPlan] = field(default_factory=list)

    def add(self, plan: MitigationPlan) -> None:
        self.plans.append(plan)

    def not_build_ready(self) -> list[MitigationPlan]:
        """Plans missing an owner or acceptance criterion — build cannot start."""        return [p for p in self.plans if not p.is_build_ready]

    def not_launch_ready(self) -> list[MitigationPlan]:
        """Plans with incomplete tasks — feature cannot ship."""        return [p for p in self.plans if not p.is_launch_ready]

    def is_build_gate_green(self) -> bool:
        return len(self.not_build_ready()) == 0

    def is_launch_gate_green(self) -> bool:
        return len(self.not_launch_ready()) == 0

    def blocked_tasks_all(self) -> list[MitigationTask]:
        return [t for p in self.plans for t in p.blocked_tasks()]

    def status_report(self) -> dict:
        return {
            "feature_id": self.feature_id,
            "total_plans": len(self.plans),
            "build_gate": "GREEN" if self.is_build_gate_green() else "RED",
            "launch_gate": "GREEN" if self.is_launch_gate_green() else "RED",
            "blocked_tasks": len(self.blocked_tasks_all()),
            "not_build_ready": [p.plan_id for p in self.not_build_ready()],
            "not_launch_ready": [p.plan_id for p in self.not_launch_ready()],
        }


